module lfsr(
    input clk,
    input reset,

    output reg [5:0] q
);

wire feedback = q[5] ^ q[4];

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
        q <= 6'b000001;
    end else begin
        q <= {q[4:0], feedback};
    end
end

endmodule
